    rows_without_S = [i for i in range(r) if 'S' not in cake[i]]
    cols_without_S = []
    for j in range(c):
        has_S = False
        for i in range(r):
            if cake[i][j] == 'S':
                has_S = True
                break
        if not has_S:
            cols_without_S.append(j)

    max_cells = 0
    # Try all possible combinations of rows and columns
    # The optimal solution is to take all possible rows first, then columns, or vice versa
    # So we can compute the maximum by considering both orders

    # Case 1: Take all possible rows first, then columns
    eaten = set()
    # Eat all safe rows
    for i in rows_without_S:
        for j in range(c):
            if cake[i][j] == '.':
                eaten.add((i, j))
    # Now eat all safe columns not already eaten
    for j in cols_without_S:
        for i in range(r):
            if cake[i][j] == '.' and (i, j) not in eaten:
                eaten.add((i, j))
    case1 = len(eaten)

    # Case 2: Take all possible columns first, then rows
    eaten = set()
    # Eat all safe columns
    for j in cols_without_S:
        for i in range(r):
            if cake[i][j] == '.':
                eaten.add((i, j))
    # Now eat all safe rows not already eaten
    for i in rows_without_S:
        for j in range(c):
            if cake[i][j] == '.' and (i, j) not in eaten:
                eaten.add((i, j))
    case2 = len(eaten)

    max_cells = max(case1, case2)
    print(max_cells)

